	kbi = 2.2; kib = kbi/33.5e-3; kpp1 = 1.72; Kmpp1 = 11.5; kib2 = kib; kb2i = kib2*5; kb24 = k24; kb42 = k42*33.5e-3/5;
	kta = kbi/1000; kat = kib; kt42 = k42*33.5e-6/5; kt24 = k24; kat2 = kib; kt2a = kib*5;
	kcanCaoff = 1; kcanCaon = kcanCaoff/0.5; kcanCaM4on = 46; kcanCaM4off = 0.0013; kcanCaM2on = kcanCaM4on; kcanCaM2off = 2508*kcanCaM4off;
	kcanCaM0on = kcanCaM4on; kcanCaM0off = 165*kcanCaM2off; k02can = k02; k20can = k20/165; k24can = k24; k42can = k20/2508;
	rcn02 = k02*pow(Ca,2)*CaM - k20*Ca2CaM; rcn24 = k24*pow(Ca,2)*Ca2CaM - k42*Ca4CaM;
	B = Btot - CaMB - Ca2CaMB - Ca4CaMB; rcn02B = k02B*pow(Ca,2)*CaMB - k20B*Ca2CaMB; rcn24B = k24B*pow(Ca,2)*Ca2CaMB - k42B*Ca4CaMB;
	rcn0B = k0Bon*CaM*B - k0Boff*CaMB; rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB; rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;
	Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN; rcnCa4CaN = kcanCaon*pow(Ca,2)*Ca2CaN - kcanCaoff*Ca4CaN;
	rcn02CaN = k02can*pow(Ca,2)*CaMCa4CaN - k20can*Ca2CaMCa4CaN; rcn24CaN = k24can*pow(Ca,2)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
	rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN; rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN; rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;
	Pix = 1 - Pb2 - Pb - Pt - Pt2 - Pa; rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2; rcnCKb2b = kb24*pow(Ca,2)*Pb2 - kb42*Pb; rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
	T = Pb + Pt + Pt2 + Pa; kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3); rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
	rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2; rcnCKta = kta*Pt - kat*Ca4CaM*Pa; rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
	rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2); rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);
	dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN); dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a));
	dCa4CaM = 1e-3*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta)); dCaMB = 1e-3*(rcn0B-rcn02B); dCa2CaMB = 1e-3*(rcn02B + rcn2B - rcn24B); dCa4CaMB = 1e-3*(rcn24B + rcn4B);
	dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2); dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt); dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2);
	dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2); dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);
	dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN); dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN); dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN); dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);
	d_finavalu[offset_1] = dCaM; d_finavalu[offset_2] = dCa2CaM; d_finavalu[offset_3] = dCa4CaM; d_finavalu[offset_4] = dCaMB; d_finavalu[offset_5] = dCa2CaMB; d_finavalu[offset_6] = dCa4CaMB;
	d_finavalu[offset_7] = dPb2; d_finavalu[offset_8] = dPb; d_finavalu[offset_9] = dPt; d_finavalu[offset_10] = dPt2; d_finavalu[offset_11] = dPa;
	d_finavalu[offset_12] = dCa4CaN; d_finavalu[offset_13] = dCaMCa4CaN; d_finavalu[offset_14] = dCa2CaMCa4CaN; d_finavalu[offset_15] = dCa4CaMCa4CaN;
	d_finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

void embedded_fehlberg_7_8_2(fp h, fp timeinst, fp* initvalu, fp* finavalu, fp* parameter, fp* error, fp* initvalu_temp, fp* finavalu_temp, fp* com){
	const fp c_1_11 = 41.0 / 840.0, c6 = 34.0 / 105.0, c_7_8= 9.0 / 35.0, c_9_10 = 9.0 / 280.0;
	const fp a2 = 2.0 / 27.0, a3 = 1.0 / 9.0, a4 = 1.0 / 6.0, a5 = 5.0 / 12.0, a6 = 1.0 / 2.0, a7 = 5.0 / 6.0, a8 = 1.0 / 6.0, a9 = 2.0 / 3.0, a10 = 1.0 / 3.0;
	const fp b31 = 1.0 / 36.0, b32 = 3.0 / 36.0, b41 = 1.0 / 24.0, b43 = 3.0 / 24.0, b51 = 20.0 / 48.0, b53 = -75.0 / 48.0, b54 = 75.0 / 48.0;
	const fp b61 = 1.0 / 20.0, b64 = 5.0 / 20.0, b65 = 4.0 / 20.0, b71 = -25.0 / 108.0, b74 = 125.0 / 108.0, b75 = -260.0 / 108.0, b76 = 250.0 / 108.0;
	const fp b81 = 31.0/300.0, b85 = 61.0/225.0, b86 = -2.0/9.0, b87 = 13.0/900.0, b91 = 2.0, b94 = -53.0/6.0, b95 = 704.0 / 45.0, b96 = -107.0 / 9.0, b97 = 67.0 / 90.0, b98 = 3.0;
	const fp b10_1 = -91.0 / 108.0, b10_4 = 23.0 / 108.0, b10_5 = -976.0 / 135.0, b10_6 = 311.0 / 54.0, b10_7 = -19.0 / 60.0, b10_8 = 17.0 / 6.0, b10_9 = -1.0 / 12.0;
	const fp b11_1 = 2383.0 / 4100.0, b11_4 = -341.0 / 164.0, b11_5 = 4496.0 / 1025.0, b11_6 = -301.0 / 82.0, b11_7 = 2133.0 / 4100.0, b11_8 = 45.0 / 82.0, b11_9 = 45.0 / 164.0, b11_10 = 18.0 / 41.0;
	const fp b12_1 = 3.0 / 205.0, b12_6 = -6.0 / 41.0, b12_7 = -3.0 / 205.0, b12_8 = -3.0 / 41.0, b12_9 = 3.0 / 41.0, b12_10 = 6.0 / 41.0;
	const fp b13_1 = -1777.0 / 4100.0, b13_4 = -341.0 / 164.0, b13_5 = 4496.0 / 1025.0, b13_6 = -289.0 / 82.0, b13_7 = 2193.0 / 4100.0, b13_8 = 51.0 / 82.0, b13_9 = 33.0 / 164.0, b13_10 = 12.0 / 41.0;
	const fp err_factor = -41.0 / 840.0;
	fp h2_7 = a2 * h, timeinst_temp;
	int i,j;

	for(j=0; 13 > j; j++){
		if(0 == j){ timeinst_temp = timeinst; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i]; } }
		else if(1 == j){ timeinst_temp = timeinst+h2_7; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0*EQUATIONS+i]); } }
		else if(2 == j){ timeinst_temp = timeinst+a3*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0*EQUATIONS+i] + b32*finavalu_temp[1*EQUATIONS+i]); } }
		else if(3 == j){ timeinst_temp = timeinst+a4*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0*EQUATIONS+i] + b43*finavalu_temp[2*EQUATIONS+i]); } }
		else if(4 == j){ timeinst_temp = timeinst+a5*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0*EQUATIONS+i] + b53*finavalu_temp[2*EQUATIONS+i] + b54*finavalu_temp[3*EQUATIONS+i]); } }
		else if(5 == j){ timeinst_temp = timeinst+a6*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0*EQUATIONS+i] + b64*finavalu_temp[3*EQUATIONS+i] + b65*finavalu_temp[4*EQUATIONS+i]); } }
		else if(6 == j){ timeinst_temp = timeinst+a7*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0*EQUATIONS+i] + b74*finavalu_temp[3*EQUATIONS+i] + b75*finavalu_temp[4*EQUATIONS+i] + b76*finavalu_temp[5*EQUATIONS+i]); } }
		else if(7 == j){ timeinst_temp = timeinst+a8*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0*EQUATIONS+i] + b85*finavalu_temp[4*EQUATIONS+i] + b86*finavalu_temp[5*EQUATIONS+i] + b87*finavalu_temp[6*EQUATIONS+i]); } }
		else if(8 == j){ timeinst_temp = timeinst+a9*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0*EQUATIONS+i] + b94*finavalu_temp[3*EQUATIONS+i] + b95*finavalu_temp[4*EQUATIONS+i] + b96*finavalu_temp[5*EQUATIONS+i] + b97*finavalu_temp[6*EQUATIONS+i]+ b98*finavalu_temp[7*EQUATIONS+i]); } }
		else if(9 == j){ timeinst_temp = timeinst+a10*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0*EQUATIONS+i] + b10_4*finavalu_temp[3*EQUATIONS+i] + b10_5*finavalu_temp[4*EQUATIONS+i] + b10_6*finavalu_temp[5*EQUATIONS+i] + b10_7*finavalu_temp[6*EQUATIONS+i] + b10_8*finavalu_temp[7*EQUATIONS+i] + b10_9*finavalu_temp[8*EQUATIONS+i]); } }
		else if(10 == j){ timeinst_temp = timeinst+h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0*EQUATIONS+i] + b11_4*finavalu_temp[3*EQUATIONS+i] + b11_5*finavalu_temp[4*EQUATIONS+i] + b11_6*finavalu_temp[5*EQUATIONS+i] + b11_7*finavalu_temp[6*EQUATIONS+i] + b11_8*finavalu_temp[7*EQUATIONS+i] + b11_9*finavalu_temp[8*EQUATIONS+i]+ b11_10 * finavalu_temp[9*EQUATIONS+i]); } }
		else if(11 == j){ timeinst_temp = timeinst; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]); } }
		else if(12 == j){ timeinst_temp = timeinst+h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]); } }

		kernel_ecc_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 0, parameter);
		kernel_cam_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 46, parameter, 1, com, 0, initvalu_temp[36]);
		kernel_cam_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 61, parameter, 1, com, 1, initvalu_temp[37]);
		kernel_cam_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 76, parameter, 1, com, 2, initvalu_temp[38]);
		kernel_fin_2(0, initvalu_temp, &finavalu_temp[j*EQUATIONS], 0, 46, 61, 76, parameter, com);

		for(i=0; i<EQUATIONS; i++){
			if (isnan(finavalu_temp[j*EQUATIONS+i]) == 1){ finavalu_temp[j*EQUATIONS+i] = 0.0001; }
			else if (isinf(finavalu_temp[j*EQUATIONS+i]) == 1){ finavalu_temp[j*EQUATIONS+i] = 0.0001; }
		}
	}

	for(i=0; i<EQUATIONS; i++){ finavalu[i]= initvalu[i] + h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i]) + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i])); }
	for(i=0; i<EQUATIONS; i++){ error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i])); }
}

int solver(fp** y, fp* x, int xmax, fp* params, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com){
	fp err_exponent, error, outside, h, h_init, tolerance, xmin;
	fp scale_min, scale_fina;
	fp* err = (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale = (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy = (fp *) malloc(EQUATIONS* sizeof(fp));
	int i, j, k;

	err_exponent = 1.0 / 7.0; h_init = 1; h = h_init; xmin = 0; tolerance = 10 / (fp)(xmax-xmin);
	x[0] = 0;
	if (xmin > xmax || 0.0 >= h){ free(err); free(scale); free(yy); return -2; }
	if (xmin == xmax){ free(err); free(scale); free(yy); return 0; }
	if ((xmax - xmin) < h ){ h = (fp)xmax - (fp)xmin; }

	for(k=1; xmax >= k; k++){
		x[k] = k-1; h = h_init; scale_fina = 1.0;
		for (j = 0; 12 > j; j++){
			error = 0; outside = 0; scale_min = 4.0;
			embedded_fehlberg_7_8(x[k], h, y[k-1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com);
			for(i=0; i<EQUATIONS; i++){ if(0 < err[i]){ error = 1; } }
			if (1 != error){ scale_fina = 4.0; break; }
			for(i=0; i<EQUATIONS; i++){
				if(0.0 == y[k-1][i]){ yy[i] = tolerance; } else{ yy[i] = fabs(y[k-1][i]); }
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale_min > scale[i]){ scale_min = scale[i]; }
			}
			scale_fina = (scale_min < 0.125 ? 0.125 : (scale_min > 4.0 ? 4.0 : scale_min));
			for(i=0; i<EQUATIONS; i++){ if ( ( tolerance * yy[i] ) < err[i] ){ outside = 1; } }
			if (0 == outside){ break; }
			h = h * scale_fina;
			if (0.9 <= h){ h = 0.9; }
			if ( x[k] + h > (fp)xmax ){ h = (fp)xmax - x[k]; }
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){ h = 0.5 * h; }
		}
		x[k] = x[k] + h;
		if ( 12 <= j ){ free(err); free(scale); free(yy); return -1; }
	}
	free(err); free(scale); free(yy); return 0;
}

int work(int xmax, int workload){
	long long time0, time1, time2, time3, time4, time5;
	time0 = get_time();
	long long memory; int i,j, status;
	fp*** y; fp** x; fp** params; fp* com;
	time1 = get_time();
	memory = workload*(xmax+1)*EQUATIONS*4;
	if(1000000000 < memory){ printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n"); return 0; }
	y = (fp ***) malloc(workload* sizeof(fp **));
	for(i=0; workload > i; i++){ y[i] = (fp**)malloc((1+xmax)*sizeof(fp*)); for(j=0; (1+xmax) > j; j++){ y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp)); } }
	x = (fp **) malloc(workload * sizeof(fp *)); for (i= 0; workload > i; i++){ x[i]= (fp *)malloc((1+xmax) *sizeof(fp)); }
	params = (fp **) malloc(workload * sizeof(fp *)); for (i= 0; workload > i; i++){ params[i]= (fp *)malloc(PARAMETERS * sizeof(fp)); }
	com = (fp*)malloc(3 * sizeof(fp));
	int d_initvalu_mem = EQUATIONS * sizeof(fp); fp* d_initvalu;
