#pragma omp parallel for
	for(i=0; workload > i; i++){
		int tid = i;
		int err_pointer = tid*EQUATIONS, scale_pointer = tid*EQUATIONS, yy_pointer = tid*EQUATIONS;
		int params_pointer = tid*PARAMETERS, initvalu_temp_pointer = tid*EQUATIONS, finavalu_temp_pointer = tid*13*EQUATIONS, com_pointer = tid*3;
		fp err_exponent = 1.0 / 7.0, h_init = 1, h = h_init, tolerance = 10 / (fp)(xmax - 0);
		fp scale_min, scale_fina, error, outside;
		int j, k;
		fp* local_err = &d_err[err_pointer]; fp* local_scale = &d_scale[scale_pointer]; fp* local_yy = &d_yy[yy_pointer];
		fp* local_params = &d_params[params_pointer]; fp* local_initvalu_temp = &d_initvalu_temp[initvalu_temp_pointer];
		fp* local_finavalu_temp = &d_finavalu_temp[finavalu_temp_pointer]; fp* local_com = &d_com[com_pointer];
		fp* local_y = &d_y[tid*((xmax+1)*EQUATIONS)]; fp* local_x = &d_x[tid*(xmax+1)];
		if (0 > xmax || 0.0 >= h){ continue; }
		if (0 == xmax){ continue; }
		if ((xmax - 0) < h ){ h = (fp)xmax - 0; }
		for(k=1; (xmax+1) > k; k++){
			long y_pointer_initial = (k-1)*EQUATIONS; long y_pointer_current = k*EQUATIONS; long x_pointer_current = k;
			local_x[x_pointer_current] = (fp)k; h = h_init; scale_fina = 1.0;
			for (j = 0; 12 > j; j++){
				error = 0; outside = 0; scale_min = 4.0;
				embedded_fehlberg_7_8_2(h, local_x[x_pointer_current], &local_y[y_pointer_initial], &local_y[y_pointer_current], local_params, local_err, local_initvalu_temp, local_finavalu_temp, local_com);
				int ii; for(ii=0; ii<EQUATIONS; ii++){ if(0 < local_err[ii]){ error = 1; } }
				if (1 != error){ scale_fina = 4.0; break; }
				for(ii=0; ii<EQUATIONS; ii++){
					if(0.0 == local_y[y_pointer_initial+ii]){ local_yy[ii] = tolerance; } else{ local_yy[ii] = fabs(local_y[y_pointer_initial+ii]); }
					local_scale[ii] = 0.8 * pow( tolerance * local_yy[ii] / local_err[ii] , err_exponent );
					if(scale_min > local_scale[ii]){ scale_min = local_scale[ii]; }
				}
				scale_fina = (scale_min < 0.125 ? 0.125 : (scale_min > 4.0 ? 4.0 : scale_min));
				for(ii=0; ii<EQUATIONS; ii++){ if ( ( tolerance * local_yy[ii] ) < local_err[ii] ){ outside = 1; } }
				if (0 == outside){ break; }
				h = h * scale_fina;
				if (0.9 <= h){ h = 0.9; }
				if ( local_x[x_pointer_current] + h > (fp)xmax ){ h = (fp)xmax - local_x[x_pointer_current]; }
				else if ( local_x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){ h = 0.5 * h; }
			}
			local_x[x_pointer_current] = local_x[x_pointer_current] + h;
			if ( 12 <= j ){ break; }
		}
	}
	time4 = get_time();
	memcpy(x, d_x, x_mem); memcpy(y, d_y, y_mem);
	time5 = get_time();
	free(y); free(x); free(params);
	time6= get_time();
	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES, COPY TO GPU MEMORY\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : RUN GPU KERNEL\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : COPY GPU DATA TO CPU MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n"); printf("%.12f s\n", (float) (time6-time0) / 1000000);
	return 0;
}

int main(int argc, char *argv []){
	int xmax, workload, mode;
	if(4 != argc){ printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 3\n", argc-1); return 0; }
	xmax = atoi(argv[1]); if(0 > xmax){ printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", xmax); return 0; }
	workload = atoi(argv[2]); if(0 > workload){ printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", workload); return 0; }
	mode = 0; mode = atoi(argv[3]); if(0 != mode && 1 != mode){ printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode); return 0; }
	if(0 == mode){ work(xmax, workload); } else{ work_2(xmax, workload); }
	return 0;
}
